import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';
import 'package:image_picker/image_picker.dart';
import 'dart:convert';
import 'dart:io';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Hybrid WebView App',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: WebViewScreen(),
    );
  }
}

class WebViewScreen extends StatefulWidget {
  @override
  _WebViewScreenState createState() => _WebViewScreenState();
}

class _WebViewScreenState extends State<WebViewScreen> {
  late WebViewController _controller;
  final ImagePicker _imagePicker = ImagePicker();
  bool _isLoading = true;

  @override
  void initState() {
    super.initState();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Hybrid WebView'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: () {
              _controller.reload();
            },
          ),
        ],
      ),
      body: Stack(
        children: [
          WebView(
            initialUrl: 'https://your-mobile-website.com',
            javascriptMode: JavascriptMode.unrestricted,
            onWebViewCreated: (WebViewController controller) {
              _controller = controller;
              _setupJavaScriptChannels();
            },
            onPageStarted: (String url) {
              setState(() {
                _isLoading = true;
              });
            },
            onPageFinished: (String url) {
              setState(() {
                _isLoading = false;
              });
              _injectJavaScript();
            },
            javascriptChannels: _createJavaScriptChannels(),
            gestureNavigationEnabled: true,
            allowsInlineMediaPlayback: true,
          ),
          if (_isLoading)
            Center(
              child: CircularProgressIndicator(),
            ),
        ],
      ),
    );
  }

  Set<JavascriptChannel> _createJavaScriptChannels() {
    return {
      JavascriptChannel(
        name: 'FlutterChannel',
        onMessageReceived: (JavascriptMessage message) {
          _handleJavaScriptMessage(message.message);
        },
      ),
      JavascriptChannel(
        name: 'CameraChannel',
        onMessageReceived: (JavascriptMessage message) {
          _handleCameraRequest(message.message);
        },
      ),
      JavascriptChannel(
        name: 'NotificationChannel',
        onMessageReceived: (JavascriptMessage message) {
          _handleNotificationRequest(message.message);
        },
      ),
    };
  }

  void _setupJavaScriptChannels() {
    print('JavaScript channels setup complete');
  }

  void _injectJavaScript() {
    String jsCode = '''
      window.FlutterBridge = {
        callNative: function(action, data) {
          FlutterChannel.postMessage(JSON.stringify({action: action, data: data}));
        },
        openCamera: function(options) {
          CameraChannel.postMessage(JSON.stringify(options));
        },
        requestNotification: function(title, body) {
          NotificationChannel.postMessage(JSON.stringify({title: title, body: body}));
        }
      };
      
      console.log('Flutter bridge initialized');
    ''';
    
    _controller.runJavascript(jsCode);
  }

  void _handleJavaScriptMessage(String message) {
    try {
      Map<String, dynamic> data = json.decode(message);
      String action = data['action'] ?? '';
      dynamic payload = data['data'];

      switch (action) {
        case 'showToast':
          _showToast(payload.toString());
          break;
        case 'getDeviceInfo':
          _sendDeviceInfo();
          break;
        case 'vibrate':
          _vibrate();
          break;
        case 'share':
          _shareContent(payload);
          break;
        default:
          print('Unknown action: $action');
      }
    } catch (e) {
      print('Error handling JavaScript message: $e');
    }
  }

  void _handleCameraRequest(String message) async {
    try {
      Map<String, dynamic> options = json.decode(message);
      String source = options['source'] ?? 'camera';
      
      ImageSource imageSource = source == 'gallery' 
          ? ImageSource.gallery 
          : ImageSource.camera;
      
      final XFile? image = await _imagePicker.pickImage(
        source: imageSource,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (image != null) {
        File imageFile = File(image.path);
        List<int> imageBytes = await imageFile.readAsBytes();
        String base64Image = base64Encode(imageBytes);
        
        String jsCallback = '''
          if (window.onCameraResult) {
            window.onCameraResult({
              success: true,
              data: 'data:image/jpeg;base64,$base64Image',
              path: '${image.path}'
            });
          }
        ''';
        
        _controller.runJavascript(jsCallback);
      } else {
        _sendCameraError('User cancelled image selection');
      }
    } catch (e) {
      _sendCameraError(e.toString());
    }
  }

  void _sendCameraError(String error) {
    String jsCallback = '''
      if (window.onCameraResult) {
        window.onCameraResult({
          success: false,
          error: '$error'
        });
      }
    ''';
    _controller.runJavascript(jsCallback);
  }

  void _handleNotificationRequest(String message) {
    try {
      Map<String, dynamic> data = json.decode(message);
      String title = data['title'] ?? 'Notification';
      String body = data['body'] ?? '';
      
      _showLocalNotification(title, body);
      
      String jsCallback = '''
        if (window.onNotificationResult) {
          window.onNotificationResult({
            success: true,
            message: 'Notification scheduled'
          });
        }
      ''';
      _controller.runJavascript(jsCallback);
    } catch (e) {
      print('Error handling notification request: $e');
    }
  }

  void _showLocalNotification(String title, String body) {
    showDialog(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: Text(title),
          content: Text(body),
          actions: [
            TextButton(
              child: Text('OK'),
              onPressed: () {
                Navigator.of(context).pop();
              },
            ),
          ],
        );
      },
    );
  }

  void _showToast(String message) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        duration: Duration(seconds: 2),
      ),
    );
  }

  void _sendDeviceInfo() {
    Map<String, dynamic> deviceInfo = {
      'platform': Platform.operatingSystem,
      'version': Platform.operatingSystemVersion,
      'isPhysicalDevice': true,
    };

    String jsCallback = '''
      if (window.onDeviceInfo) {
        window.onDeviceInfo(${json.encode(deviceInfo)});
      }
    ''';
    _controller.runJavascript(jsCallback);
  }

  void _vibrate() {
    print('Vibrate requested');
  }

  void _shareContent(dynamic content) {
    print('Share content: $content');
  }
}